-- W1.6 questions batch 7197/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-e7b0146b-moex-00070', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-0c727b96', 'sub-locality-e7b0146b-07', NULL, 'essay', '2022年是「世界遺產公約」（TheWorldHeritageConvention）頒布 50 周
年，同時也是臺灣「文化資產保存法」頒布 40周年。請舉例說明臺灣的
文化資產法令受「世界遺產公約」影響的部分，以及請就臺灣文化資產
保存的觀念與制度上該如何銜接國際共識，提出個人的觀察看法與政策
建議。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "68a46cf010c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化資產概論與法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00071', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-0c727b96', 'sub-locality-e7b0146b-07', NULL, 'essay', '近幾年來，臺灣的私有產權被指定或登錄為法定文化資產的爭議案件日
益增加。民國 110 年底，司法院釋字第 813號針對「歷史建築所定著之
土地為第三人所有之補償案」作出解釋，大法官認為指定或登錄文化資
產致人民財產權遭受逾越其社會責任所應忍受範圍之損失，而形成個人
之特別犧牲時，國家應予相當補償。請問，您對此解釋案有何看法？而
目前「文化資產保存法」相關條文又該如何修法因應？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "68a46cf010c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化資產概論與法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00072', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-0c727b96', 'sub-locality-e7b0146b-07', NULL, 'essay', '促進轉型正義委員會（簡稱促轉會）任期已於民國 111 年 5 月底屆滿，
促轉會完成任務總結報告後，即依法解散其任務型機關的身分，並且在
促轉會解散後，移交相關任務給各主管機關。其中保存「不義遺址」的
工作事項，由文化主管機關辦理。請問，從目前「文化資產保存法」的
體系來看，「不義遺址」資料庫的名單該如何進入文化資產審議程序？以
及該如何跟社會大眾進行教育詮釋？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "68a46cf010c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化資產概論與法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00073', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-0c727b96', 'sub-locality-e7b0146b-07', NULL, 'essay', '2016年我國「文化資產保存法」參酌日本「史跡名勝天然紀念物」的概
念，新增「史蹟」成為有形文化資產的九個類別之一。但在史蹟的登錄
基準上，我國強調的是以遺構或史料佐證曾發生歷史上重要事件之場所
或場域，如古戰場、拓墾（植）場所、災難場所等。請問，當史蹟以史
料佐證作為曾發生歷史事件的登錄依據時，其定著土地的範圍該如何劃
定？以及史蹟該如何從「紀念性」的角度區分與「紀念建築」之間的差
異，請舉例說明之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "68a46cf010c5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0304", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化資產概論與法規", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00074', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-8e8338b7', 'sub-locality-e7b0146b-03', NULL, 'essay', '宋人嚴羽《滄浪詩話．詩辨》：「詩者，吟詠情性也。盛唐諸人惟在興趣，
羚羊掛角，無跡可求。故其妙處，透徹玲瓏，不可湊泊，如空中之音，
相中之色，水中之月，鏡中之象，言有盡而意無窮。近代諸公，乃作奇
特解會，遂以文字為詩，以才學為詩，以議論為詩。夫豈不工？終非古
人之詩也。」請依本段文句，說明嚴羽判析盛唐詩與宋詩之特色及其所
倡議詩學觀念，並舉例說明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "1bb052cf7d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "本國文學概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00075', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-8e8338b7', 'sub-locality-e7b0146b-03', NULL, 'essay', '常言道：文史哲不分家。歷史，記載過去時空所發生的事件和行動，而
文學創作者則取材這些事件，藉著獨特觀點與文采，進行評述或抒發情
思，形成另一種記載歷史的方式，甚至影響後世的認知和感受。請舉出
以唐玄宗與楊貴妃史事為素材之文學作品（文體不拘）三部，並敘述其
內容與意涵。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "1bb052cf7d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "本國文學概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00076', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-8e8338b7', 'sub-locality-e7b0146b-03', NULL, 'essay', '1980年代進入臺灣新電影時代之後，改編大量臺灣文學作品，近期《他
們在島嶼寫作》系列，介紹了幾位在文壇各領風騷臺灣作家的身影。你
認為此類紀錄片反映的文學價值為何？請以楊牧、七等生的作品為例，
說明作家各具的寫作風格及其文學成就。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "1bb052cf7d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "本國文學概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00077', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-8e8338b7', 'sub-locality-e7b0146b-03', NULL, 'essay', '從日治時期到當代，臺灣經歷過兩次現代主義文學風潮，請分別說明形成
的時代背景與代表作家，並舉例說明現代主義興起對文學發展的影響。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "1bb052cf7d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0103", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "本國文學概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00078', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-15fd680d', 'sub-locality-e7b0146b-04', NULL, 'essay', '「藝術」包含的範圍及類型相當廣泛，一般區分為文學、音樂、繪畫、雕
刻、建築、舞蹈、戲劇及電影等八大類，其後攝影、工藝或數位藝術等
亦被納入。有關藝術分類之方法，隨時代或地區差異等因素而不斷改變，
目前國內慣以「視覺藝術」及「表演藝術」來統整上述不同類別之藝術
形式，逐漸打破過往的分類標準。基於當下環境有越來越重視跨領域、
跨學科整合之趨勢，您認為現行分類方法有何優缺得失，可能進行何種
增刪或調整，以因應未來之實際發展需求？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "b85ff88d39d5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "藝術概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00079', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-15fd680d', 'sub-locality-e7b0146b-04', NULL, 'essay', '隨著「全球化」文化現象的不斷推進，跨國、跨地區或跨文化之間的整
合及流通無可避免，然而維持一定程度的「在地化」，亦同時成為回應或
制衡該現象之對應策略。請列舉一位活躍於國際藝術界的亞洲當代藝術
家為例，試論其如何跨越地理疆界，順應國際趨勢又能彰顯自身文化特
質、主體性，進而達到「全球在地化」（Glocalization）的平衡共構關係。
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "b85ff88d39d5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "藝術概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL)
